#include <iostream>
using namespace std;

// ==========================================
// 1. БАЗОВИЙ КЛАС
// ==========================================
class Character {
protected:
    int hp; // Захищене поле: доступне спадкоємцям, але закрите для main()

public:
    // Базовий конструктор
    Character(int h) : hp(h) {}

    // ВАЖЛИВО: Віртуальний деструктор
    virtual ~Character() {
        cout << "[Character] Базовий деструктор\n";
    }

    // Успадковані геттери та сеттери
    int getHp() const { return hp; }
    void setHp(int h) { hp = h; }
};

// ==========================================
// 2. ПОХІДНИЙ КЛАС
// ==========================================
class Mage : public Character {
private:
    int* spells;    // Динамічний масив шкоди від заклинань
    int spellCount; // Кількість заклинань

public:
    // Виклик конструктора базового класу через список ініціалізації
    Mage(int h, int count) : Character(h), spellCount(count) {
        spells = new int[count];
        for(int i = 0; i < count; i++) {
            spells[i] = 10 * (i + 1); // Базова шкода: 10, 20, 30...
        }
    }

    // --- ПРАВИЛО ТРЬОХ ДЛЯ СПАДКОЄМЦЯ ---

    // 1. Деструктор
    ~Mage() override {
        delete[] spells;
        cout << "[Mage] Деструктор спадкоємця (пам'ять звільнено)\n";
    }

    // 2. Конструктор копіювання (явно копіюємо Character!)
    Mage(const Mage& other) : Character(other), spellCount(other.spellCount) {
        spells = new int[spellCount];
        for(int i = 0; i < spellCount; i++) {
            spells[i] = other.spells[i];
        }
    }

    // 3. Оператор присвоєння =
    Mage& operator=(const Mage& other) {
        if (this == &other) return *this;

        // ВАЖЛИВО: присвоєння базової частини
        Character::operator=(other);

        delete[] spells; 
        spellCount = other.spellCount;
        spells = new int[spellCount];
        for(int i = 0; i < spellCount; i++) {
            spells[i] = other.spells[i];
        }
        return *this;
    }

    // --- ПЕРЕВАНТАЖЕННЯ ОПЕРАТОРІВ ---

    // Оператор + : Злиття двох магів
    Mage operator+(const Mage& other) const {
        // Сумуємо HP та загальну кількість заклинань
        Mage result(this->hp + other.hp, this->spellCount + other.spellCount);

        // Копіюємо заклинання першого мага
        for(int i = 0; i < this->spellCount; i++) {
            result.spells[i] = this->spells[i];
        }
        // Додаємо заклинання другого мага
        for(int i = 0; i < other.spellCount; i++) {
            result.spells[this->spellCount + i] = other.spells[i];
        }
        return result;
    }

    // Оператор == : Перевірка на рівність
    bool operator==(const Mage& other) const {
        // 1. Перевіряємо базову частину (HP)
        if (this->hp != other.hp) return false;
        // 2. Перевіряємо розміри масивів
        if (this->spellCount != other.spellCount) return false;
        // 3. Перевіряємо кожен елемент масиву
        for(int i = 0; i < spellCount; i++) {
            if (this->spells[i] != other.spells[i]) return false;
        }
        return true;
    }

    // Оператор != : Перевірка на нерівність
    bool operator!=(const Mage& other) const {
        return !(*this == other); // Використовуємо вже написаний operator==
    }

    // Оператор << (friend)
    friend ostream& operator<<(ostream& out, const Mage& m) {
        // m.hp доступне, бо ми friend класу Mage, який успадкував hp як protected
        out << "[HP: " << m.hp << ", Шкода магії: {";
        for(int i = 0; i < m.spellCount; i++) {
            out << m.spells[i] << (i < m.spellCount - 1 ? ", " : "");
        }
        out << "}]";
        return out;
    }
};

int main() {
    Mage fireMage(100, 2);  // HP 100, 2 заклинання (10, 20)
    Mage iceMage(50, 3);    // HP 50, 3 заклинання (10, 20, 30)
    Mage fireClone = fireMage; // Копія вогняного мага

    cout << "Вогняний маг: " << fireMage << endl;
    cout << "Крижаний маг: " << iceMage << endl;

    // Перевірка операторів == та !=
    cout << "\nfireMage == fireClone? " << (fireMage == fireClone ? "Так" : "Ні") << endl;
    cout << "fireMage != iceMage? " << (fireMage != iceMage ? "Так" : "Ні") << endl;

    // Виклик operator+
    Mage archMage = fireMage + iceMage;

    // Виклик успадкованого сеттера (setHp з Character)
    archMage.setHp(300);

    cout << "\nАрхімаг (після злиття та сеттера): " << archMage << endl;

    // Виклик успадкованого геттера
    cout << "Отримано HP через геттер: " << archMage.getHp() << "\n" << endl;

    return 0;
}
